#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    int x = *(int *)b - *(int *)a; // descending
    return x;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    const int MAXN = 200000 + 5;
    static int freq[MAXN];
    static int distinct[MAXN];
    while (T--) {
        int N; scanf("%d", &N);
        int distinctCnt = 0;
        for (int i = 0; i < N; ++i) {
            int x; scanf("%d", &x);
            if (freq[x] == 0) distinct[distinctCnt++] = x;
            freq[x]++;
        }
        int *f = (int *)malloc(distinctCnt * sizeof(int));
        for (int i = 0; i < distinctCnt; ++i) f[i] = freq[distinct[i]];
        qsort(f, distinctCnt, sizeof(int), cmp_desc);
        long long pref = 0, ans = 0;
        for (int i = 0; i < distinctCnt; ++i) {
            pref += f[i];
            long long d = i + 1;
            long long cand = pref - (pref % d);
            if (cand > ans) ans = cand;
        }
        printf("%lld\n", ans);
        // reset frequencies
        for (int i = 0; i < distinctCnt; ++i) freq[distinct[i]] = 0;
        free(f);
    }
    return 0;
}

