        int N; cin>>N;
        distinct.clear();
        for(int i=0;i<N;++i){
            int x; cin>>x;
            if(freq[x]==0) distinct.push_back(x);
            ++freq[x];
        }
        vector<int> f; f.reserve(distinct.size());
        for(int v: distinct) f.push_back(freq[v]);
        sort(f.begin(), f.end(), greater<int>());
        long long pref=0, ans=0;
        for(size_t i=0;i<f.size();++i){
            pref+=f[i];
            long long d=i+1;
            long long cand = pref - (pref % d);
            ans = max(ans, cand);
        }
        cout<<ans<<"\n";
        for(int v: distinct) freq[v]=0;
    }
    return 0;
}

