import java.io.*;
import java.util.*;

public class Main {
    static final int MAXN = 200000 + 5;
    static int[] freq = new int[MAXN];
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        int[] distinct = new int[MAXN];
        while (T-- > 0) {
            int N = fs.nextInt();
            int distinctCnt = 0;
            for (int i = 0; i < N; i++) {
                int x = fs.nextInt();
                if (freq[x] == 0) distinct[distinctCnt++] = x;
                freq[x]++;
            }
            int[] f = new int[distinctCnt];
            for (int i = 0; i < distinctCnt; i++) f[i] = freq[distinct[i]];
            Arrays.sort(f);
            // reverse to descending
            long ans = 0, pref = 0;
            for (int i = distinctCnt - 1, d = 1; i >= 0; i--, d++) {
                pref += f[i];
                long cand = pref - (pref % d);
                if (cand > ans) ans = cand;
            }
            sb.append(ans).append('\n');
            // reset
            for (int i = 0; i < distinctCnt; i++) freq[distinct[i]] = 0;
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

