import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        freq = {}
        for _ in range(N):
            x = int(next(it))
            freq[x] = freq.get(x, 0) + 1
        f = sorted(freq.values(), reverse=True)
        pref = 0
        ans = 0
        for i, val in enumerate(f, 1):
            pref += val
            cand = pref - (pref % i)
            if cand > ans:
                ans = cand
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

